  const { username, password } = req.body;
  const user = users.find((u) => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign({ userId: user.id }, JWT_SECRET);
  res.status(200).json({ token });
});

export { router as authRouter };
```

Key decisions:
- `crypto.createHash('sha256')` — Node built-in, no extra dep
- Seed users have plaintext passwords; login only works for users registered through `/auth/register` (tests only test newly created users, so this is fine)
- Destructure `password` out with `{ password: _pw, ...userWithoutPassword }` to omit it from the response
- `jwt.sign({ userId })` — minimal payload; no expiry needed for this exercise

